def find_peak_element(arr):
    """
    Bir bitonik dizisindeki tepe noktasını (en büyük öğe) bulan fonksiyon.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = left + (right - left) // 2

        if arr[mid] < arr[mid + 1]:
            left = mid + 1
        else:
            right = mid

    return left


def binary_search_ascending(arr, target, left, right):
    """
    Artan bir alt dizide ikili arama yapan fonksiyon.
    """
    while left <= right:
        mid = left + (right - left) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1


def binary_search_descending(arr, target, left, right):
    """
    Azalan bir alt dizide ikili arama yapan fonksiyon.
    """
    while left <= right:
        mid = left + (right - left) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            right = mid - 1
        else:
            left = mid + 1

    return -1


def search_in_bitonic_array(arr, target):
    """
    Bitonik bir dizide bir hedefi arayan fonksiyon.
    """
    peak_index = find_peak_element(arr)

    # Önce artan kısımda ara
    index = binary_search_ascending(arr, target, 0, peak_index - 1)
    if index != -1:
        return index

    # Değilse, azalan kısımda ara
    index = binary_search_descending(arr, target, peak_index, len(arr) - 1)
    if index != -1:
        return index

    return -1

if __name__ == '__main__':
    # Örnek Kullanım
    bitonic_array = [1, 3, 5, 7, 9, 10, 8, 6, 4, 2, 0]
    target_element = 6

    index = search_in_bitonic_array(bitonic_array, target_element)

    if index != -1:
        print(f"{target_element} sayısı, {index} konumunda bulundu.")
    else:
        print(f"{target_element} sayısı, dizide bulunamadı.")
